// → client asks what tools exist
{ "jsonrpc": "2.0", "id": 1, "method": "tools/list" }

// ← server advertises the new tool
{ "jsonrpc": "2.0", "id": 1, "result": {
    "tools": [{
      "name": "top_products",
      "description": "List the best-selling products.",
      "inputSchema": { "type": "object",
        "properties": { "limit": { "type": "integer" } } }
    }]
} }

// → model calls it for the top 5
{ "jsonrpc": "2.0", "id": 2, "method": "tools/call",
  "params": { "name": "top_products",
    "arguments": { "limit": 5 } } }

// ← server would reply to id 2 with result.content (the rows)
